<template>
  <div id="detail" class="col-2" :class="[{active: scrollActive == true}]">
    <button class="close" @click="goBack()">
        <span class="line1"></span>
        <span class="line2"></span>
    </button>
    <!--intro-->
    <div class="intro">
        <div class="tit ko">
            쉐정 2020 설 선물세트 디자인
            <p class="tit-sub">‌2020 / Package</p>
        </div>
    </div>
    <div class="inner">
      <!-- left -->
      <div class="sec left">
          <img src="../../../assets/img/08_chejung_20/01.jpg" alt="쉐정 2020 설 선물세트 디자인">
          <img src="../../../assets/img/08_chejung_20/02.jpg" alt="쉐정 2020 설 선물세트 디자인">
          <img src="../../../assets/img/08_chejung_20/03.jpg" alt="쉐정 2020 설 선물세트 디자인">
      </div>
      <!-- right -->
      <div class="sec right">
          <p>쉐정 2020 설 선물세트 디자인</p>
          <p>깔끔한 화이트 박스에 작은 창을 내서 신선한 고기가 더 강조되도록 디자인하였습니다. 각 고기 등급과 종류에 맞는 스티커를 활용하여 하나의 박스로 사용할 수 있도록 구성하였습니다.
          </p>
          <p>디자인. 최지우</p>
      </div>
    </div>
    <div class="copy">
      <div class="title">CHEJUNG 2020 New Year Gift Box Design</div>
      <div class="desiner">©Designer Jiwoo</div>
    </div>
  </div>
</template>

<script>
export default {
    name: "chejung20",
    inheritAttrs: false,
    data() {
        return {
        scrollActive: false,
        }
    },
    methods: {
        goBack(){
            this.$router.go(-1);
        },
        scrollEvent(){
            const scrollTop = window.pageYOffset || document.documentElement.scrollTop
            const currentScrollTop = document.querySelector(".inner").offsetTop;
            if(scrollTop > currentScrollTop){
                this.scrollActive = true
            } else{
                this.scrollActive = false
            }
        },
    },
    mounted(){
        document.addEventListener('scroll', this.scrollEvent);
    },
    unmounted() {
        document.removeEventListener('scroll', this.scrollEvent);
    },
}
</script>

